class Solution:
    def validIPAddress(self, queryIP):
        """
        :type queryIP: str
        :rtype: str
        """
        def isValidIPv4(s):
            parts = s.split('.')
            if len(parts) != 4:
                return False
            for part in parts:
                if not part or len(part) > 3:
                    return False
                if part[0] == '0' and len(part) > 1:
                    return False
                if not part.isdigit():
                    return False
                if int(part) > 255:
                    return False
            return True

        def isValidIPv6(s):
            parts = s.split(':')
            if len(parts) != 8:
                return False
            for part in parts:
                if not part or len(part) > 4:
                    return False
                if not all(c in '0123456789abcdefABCDEF' for c in part):
                    return False
            return True

        if isValidIPv4(queryIP):
            return "IPv4"
        elif isValidIPv6(queryIP):
            return "IPv6"
        else:
            return "Neither"
